// ─── Lookup helpers ───────────────────────────────────────────────────────────

/** O(1) lookup by slug — covers both static JOB_LISTINGS and scraped Tempo-Team jobs */
export const JOB_MAP: Record<string, JobListing> = Object.fromEntries(
  [
    ...JOB_LISTINGS,
    ...(rawTempoTeamJobs as RawTempoTeamJob[]).map(tempoTeamJobToListing),
  ].map((j) => [j.slug, j])
);

/** All active jobs for a given agency slug.
 *  Handles slug aliases (e.g. "randstad-nederland" → "randstad")
 *  and Tempo-Team scraped jobs from tempo-team-jobs.json.
 */
export function getJobsByAgency(agencySlug: string): JobListing[] {
  // Tempo-Team: serve scraped live jobs from tempo-team-jobs.json
  if (TEMPO_TEAM_AGENCY_SLUGS.has(agencySlug)) {
    return (rawTempoTeamJobs as RawTempoTeamJob[]).map(tempoTeamJobToListing);
  }
  // Resolve slug alias (e.g. "randstad-nederland" → "randstad")
  const resolved = AGENCY_SLUG_ALIASES[agencySlug] ?? agencySlug;
  return JOB_LISTINGS
    .filter((j) => j.agencySlug === resolved && j.isActive)
    .sort((a, b) => (b.isFeatured ? 1 : 0) - (a.isFeatured ? 1 : 0));
}

/** All active jobs in a given city */
export function getJobsByCity(city: string): JobListing[] {
  return JOB_LISTINGS
    .filter((j) => j.city.toLowerCase() === city.toLowerCase() && j.isActive)
    .sort((a, b) => (b.isFeatured ? 1 : 0) - (a.isFeatured ? 1 : 0));
}

/** All active jobs of a given type */
export function getJobsByType(jobType: string): JobListing[] {
  return JOB_LISTINGS
    .filter((j) => j.jobType === jobType && j.isActive)
    .sort((a, b) => (b.isFeatured ? 1 : 0) - (a.isFeatured ? 1 : 0));
}

/** Top jobs for an agency, capped at n, sorted by salary descending */
export function getTopJobsForAgency(agencySlug: string, n = 6): JobListing[] {
  return getJobsByAgency(agencySlug)
    .sort((a, b) => b.salaryMax - a.salaryMax)
    .slice(0, n);
}

/** Number of active jobs for a given agency slug (respects slug aliases + Tempo-Team) */
export function getJobCountForAgency(agencySlug: string): number {
  return getJobsByAgency(agencySlug).length;
}

